function maxProfit(inventory, orders) {
    const mod = 1e9 + 7;
    inventory.sort((a, b) => b - a).push(0);
    let n = inventory.length, ans = 0n, count = 1n;
    for (let i = 0; i < n - 1; ++i, ++count) {
        const diff = BigInt(inventory[i] - inventory[i + 1]);
        if (count * diff < orders) {
            orders -= count * diff;
            ans = (ans + (((BigInt(inventory[i]) + BigInt(inventory[i + 1]) + 1n) * diff) / 2n) % mod * count) % mod;
        } else {
            const q = BigInt(orders / count);
            const r = BigInt(orders % count);
            ans = (ans + (((BigInt(inventory[i]) + BigInt(inventory[i]) - q + 1n) * q) / 2n) % mod * count) % mod;
            ans = (ans + r * (BigInt(inventory[i]) - q)) % mod;
            break;
        }
    }
    return parseInt(ans);
}
```

    1. Sort the inventory array in decreasing order and append 0 to the end.
2. Initialize a variable `count` to 1. This variable represents the number of balls that have the same value.
3. Iterate through the inventory.
    - Calculate the difference between the current element and the next element.
    - If `count * diff` is smaller than the remaining `orders`, update `orders` and the `ans` appropriately. Increment the `count` variable.
    - If `count * diff` is greater than or equal to `orders`, calculate the multiples and remainders of the orders in the current batch. Update the answer and break the loop.
4. Return the calculated answer mod 1e9 + 7.

